import React, { useEffect, useState } from "react";
import { Alert, Card, Col, Row } from "react-bootstrap";

import { reportsApi } from "../utils/api";

function DashboardPage() {
  const [counts, setCounts] = useState({});
  const [error, setError] = useState("");

  useEffect(() => {
    reportsApi
      .counts()
      .then((response) => {
        setCounts(response.data);
        setError("");
      })
      .catch(() => {
        setCounts({});
        setError("Backend is not reachable right now. Start the API and refresh.");
      });
  }, []);

  const stats = [
    { label: "Enquiries", value: counts.enquiries || 0 },
    { label: "Quotations", value: counts.quotations || 0 },
    { label: "Sales Orders", value: counts.sales_orders || 0 },
    { label: "Invoices", value: counts.invoices || 0 },
  ];

  return (
    <div>
      <h1 className="mb-4">Dashboard</h1>
      {error && <Alert variant="warning">{error}</Alert>}
      <Row className="g-4">
        {stats.map((stat) => (
          <Col md={6} xl={3} key={stat.label}>
            <Card className="dashboard-card border-0 shadow-sm">
              <Card.Body>
                <p className="text-muted mb-2">{stat.label}</p>
                <h2 className="mb-0">{stat.value}</h2>
              </Card.Body>
            </Card>
          </Col>
        ))}
      </Row>
    </div>
  );
}

export default DashboardPage;
